solution_code:
#include <iostream>

class Vector2D {
    int m_x, m_y;
public:
    Vector2D(int x, int y) : m_x{x}, m_y{y} {}

    friend Vector2D operator+(const Vector2D& a, const Vector2D& b);

    bool operator==(const Vector2D& rhs) const {
        return m_x == rhs.m_x && m_y == rhs.m_y;
    }

    bool operator!=(const Vector2D& rhs) const {
        return !(*this == rhs);
    }

    void print(const char* label) const {
        std::cout << label << ": " << m_x << ' ' << m_y << '\n';
    }
};

Vector2D operator+(const Vector2D& a, const Vector2D& b) {
    return Vector2D{a.m_x + b.m_x, a.m_y + b.m_y};
}

int main() {
    int x1, y1, x2, y2;
    std::cin >> x1 >> y1 >> x2 >> y2;
    Vector2D A{x1, y1};
    Vector2D B{x2, y2};
    (A + B).print("sum");
    std::cout << "equal: "     << (A == B) << '\n';
    std::cout << "not_equal: " << (A != B) << '\n';
    return 0;
}

