#include <iostream>

struct Counter {
    int m_val;
    Counter(int v) : m_val{v} {}

    Counter& operator++() {
        ++m_val;
        return *this;
    }

    Counter operator++(int) {
        Counter old{m_val};
        ++m_val;
        return old;
    }

    int value() const { return m_val; }
};

int main() {
    int start;
    std::cin >> start;
    Counter c{start};
    Counter pre = ++c;
    std::cout << "pre: "   << pre.value()  << '\n';
    Counter post = c++;
    std::cout << "post: "  << post.value() << '\n';
    std::cout << "final: " << c.value()    << '\n';
    return 0;
}
